# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1000000;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];

int bfs_dist_buf[31][31];
Point bfs_parent_buf[31][31];

char bfs_move(Point start, Point target) {
    if (start == target) return '.';

    memset(bfs_dist_buf, -1, sizeof(bfs_dist_buf));
    std::queue<Point> q;
    bfs_dist_buf[start.r][start.c] = 0;
    bfs_parent_buf[start.r][start.c] = {-1, -1};
    q.push(start);

    while (!q.empty()) {
        Point cur = q.front(); q.pop();

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall_grid[np.r][np.c]) continue;
            if (bfs_dist_buf[np.r][np.c] != -1) continue;

            bfs_dist_buf[np.r][np.c] = bfs_dist_buf[cur.r][cur.c] + 1;
            bfs_parent_buf[np.r][np.c] = cur;
            q.push(np);

            if (np == target) {
                Point step = np;
                while (!(bfs_parent_buf[step.r][step.c] == start)) {
                    step = bfs_parent_buf[step.r][step.c];
                }
                for (int i = 0; i < 4; i++) {
                    if (start.r + DIRS[i].r == step.r && start.c + DIRS[i].c == step.c) {
                        return DIR_MOVE[i];
                    }
                }
                return '.';
            }
        }
    }
    return '.';
}

bool can_build_wall(Point pos, int builder_id) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall_grid[pos.r][pos.c]) return false;

    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (i == builder_id) continue;
        if (humans[i].pos == pos) return false;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall_grid, false, sizeof(wall_grid));

    // Evaluate rectangular safe zones
    struct Option {
        int r1, r2, c1, c2;
        std::vector<Point> walls;
        int n_pets;
        int area;
        double score;
    };

    std::vector<Option> options;

    // Single horizontal walls
    for (int w = 3; w <= GRID_SIZE - 2; w++) {
        // Top: [1..w-1] x [1..30]
        int pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r <= w - 1) pets_in++;
        }
        int area = (w - 1) * GRID_SIZE;
        double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        std::vector<Point> ws;
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({1, w - 1, 1, GRID_SIZE, ws, pets_in, area, sc});

        // Bottom: [w+1..30] x [1..30]
        pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= w + 1) pets_in++;
        }
        area = (GRID_SIZE - w) * GRID_SIZE;
        sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        ws.clear();
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({w + 1, GRID_SIZE, 1, GRID_SIZE, ws, pets_in, area, sc});
    }

    // Corner rectangles - only test reasonable sizes
    auto add_corner = [&](int r1, int r2, int c1, int c2, std::vector<Point> ws) {
        int pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= r1 && pet.pos.r <= r2 && pet.pos.c >= c1 && pet.pos.c <= c2) pets_in++;
        }
        int area = (r2 - r1 + 1) * (c2 - c1 + 1);
        double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        options.push_back({r1, r2, c1, c2, ws, pets_in, area, sc});
    };

    for (int h = 5; h <= 22; h += 2) {
        for (int w = 5; w <= 22; w += 2) {
            // Top-left: [1..h] x [1..w]
            if (h + 1 <= GRID_SIZE && w + 1 <= GRID_SIZE) {
                std::vector<Point> ws;
                for (int c = 1; c <= w; c++) ws.push_back({h + 1, c});
                for (int r = 1; r <= h; r++) ws.push_back({r, w + 1});
                add_corner(1, h, 1, w, ws);
            }

            // Top-right: [1..h] x [30-w+1..30]
            {
                int cs = GRID_SIZE - w + 1;
                int cw = cs - 1;
                if (h + 1 <= GRID_SIZE && cw >= 1) {
                    std::vector<Point> ws;
                    for (int c = cs; c <= GRID_SIZE; c++) ws.push_back({h + 1, c});
                    for (int r = 1; r <= h; r++) ws.push_back({r, cw});
                    add_corner(1, h, cs, GRID_SIZE, ws);
                }
            }

            // Bottom-left: [30-h+1..30] x [1..w]
            {
                int rs = GRID_SIZE - h + 1;
                int rw = rs - 1;
                if (rw >= 1 && w + 1 <= GRID_SIZE) {
                    std::vector<Point> ws;
                    for (int c = 1; c <= w; c++) ws.push_back({rw, c});
                    for (int r = rs; r <= GRID_SIZE; r++) ws.push_back({r, w + 1});
                    add_corner(rs, GRID_SIZE, 1, w, ws);
                }
            }

            // Bottom-right: [30-h+1..30] x [30-w+1..30]
            {
                int rs = GRID_SIZE - h + 1;
                int rw = rs - 1;
                int cs = GRID_SIZE - w + 1;
                int cw = cs - 1;
                if (rw >= 1 && cw >= 1) {
                    std::vector<Point> ws;
                    for (int c = cs; c <= GRID_SIZE; c++) ws.push_back({rw, c});
                    for (int r = rs; r <= GRID_SIZE; r++) ws.push_back({r, cw});
                    add_corner(rs, GRID_SIZE, cs, GRID_SIZE, ws);
                }
            }
        }
    }

    // Feasibility penalty
    for (auto& opt : options) {
        int nw = opt.walls.size();
        double feasibility = 1.0;
        int max_walls = M * 80;
        if (nw > max_walls) {
            feasibility = (double)max_walls / nw;
        }
        opt.score *= feasibility;
    }

    std::sort(options.begin(), options.end(), [](const Option& a, const Option& b) {
        return a.score > b.score;
