                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int sd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move_toward(hp, best_stand);
                    }
                }
            }
        } else {
            // Move humans to safe zone
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                // If using box, make sure humans are OUTSIDE the box
                if (use_box) {
                    bool inside = (hp.r > best_box.r1 && hp.r < best_box.r2 &&
                                   hp.c > best_box.c1 && hp.c < best_box.c2);
                    bool on_wall = wall_grid[hp.r][hp.c];
                    if (inside || on_wall) {
                        // Need to escape - but if box is complete, can't escape
                        // Move toward safe_target anyway
                        actions[i] = bfs_move_toward(hp, safe_target);
                    } else {
                        // Already outside, move to spread out
                        Point target = safe_target;
                        target.c = std::max(1, std::min(GRID_SIZE, safe_target.c - M/2 + i));
                        actions[i] = bfs_move_toward(hp, target);
                    }
                } else {
                    // Dual horizontal: move toward safe zone center
                    Point target;
                    if (hp.r < best_dual_h.row_top) {
                        target = {best_dual_h.row_top / 2, GRID_SIZE / 2};
                    } else if (hp.r > best_dual_h.row_bot) {
                        target = {(best_dual_h.row_bot + GRID_SIZE + 1) / 2, GRID_SIZE / 2};
                    } else {
                        // Trapped in middle - try to move out
                        if (best_dual_h.area_above >= best_dual_h.area_below) {
                            target = {1, hp.c};
                        } else {
                            target = {GRID_SIZE, hp.c};
                        }
                    }
                    actions[i] = bfs_move_toward(hp, target);
                }
            }
        }

        // Validate all actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall_grid[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Check for move conflicts
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                for (const auto& tw : tentative_walls) {
                    if (np == tw) {
                        actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall_grid[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (np.r >= 1 && np.r <= GRID_SIZE && np.c >= 1 && np.c <= GRID_SIZE && !wall_grid[np.r][np.c]) {
                    humans[i].pos = np;
                }
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
