# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1000000;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];

int bfs_dist[31][31];

char bfs_move_toward(Point start, Point target) {
    if (start == target) return '.';

    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    q.push(start);

    int parent_dir[31][31];
    memset(parent_dir, -1, sizeof(parent_dir));

    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        if (cur == target) break;

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall_grid[np.r][np.c]) continue;
            if (bfs_dist[np.r][np.c] != -1) continue;

            bfs_dist[np.r][np.c] = bfs_dist[cur.r][cur.c] + 1;
            parent_dir[np.r][np.c] = d;
            q.push(np);
        }
    }

    if (bfs_dist[target.r][target.c] == -1) return '.';

    // Trace back from target to find first step
    Point cur = target;
    while (true) {
        int d = parent_dir[cur.r][cur.c];
        Point prev = {cur.r - DIRS[d].r, cur.c - DIRS[d].c};
        if (prev == start) {
            return DIR_MOVE[d];
        }
        cur = prev;
    }
}

bool can_build_wall(Point pos, int builder_id) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall_grid[pos.r][pos.c]) return false;

    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].pos == pos) return false;
    }
    return true;
}

enum Strategy { DUAL_H, DUAL_V, SINGLE_H_TOP, SINGLE_H_BOT, SINGLE_V_LEFT, SINGLE_V_RIGHT };

struct Config {
    Strategy strat;
    std::vector<Point> walls;
    int safe_r1, safe_r2, safe_c1, safe_c2; // bounding box of safe zone (for human targeting)
    int safe_area;
    int pets_in_safe;
    double score;
    // For dual walls: which side(s) to put humans
    int side; // 0=above/left, 1=below/right, 2=both
    // For dual: the two wall positions
    int wall_pos1, wall_pos2;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall_grid, false, sizeof(wall_grid));

    // Evaluate configurations
    Config best_config;
    best_config.score = -1;

    // Helper: count pets in region
    auto count_pets_in_rows = [&](int r_lo, int r_hi) {
        int cnt = 0;
        for (const auto& p : pets)
            if (p.pos.r >= r_lo && p.pos.r <= r_hi) cnt++;
        return cnt;
    };
    auto count_pets_in_cols = [&](int c_lo, int c_hi) {
        int cnt = 0;
        for (const auto& p : pets)
            if (p.pos.c >= c_lo && p.pos.c <= c_hi) cnt++;
        return cnt;
    };

    // Dual Horizontal: walls at rows r1 and r2, pets between, humans above + below
    for (int r1 = 2; r1 <= 14; r1++) {
        for (int r2 = r1 + 3; r2 <= 29; r2++) {
            int pets_above = count_pets_in_rows(1, r1 - 1);
            int pets_below = count_pets_in_rows(r2 + 1, GRID_SIZE);
            int pets_middle = N - pets_above - pets_below;
            // Count pets ON the wall rows (they'll be pushed by wall or block it)
            int pets_on_wall = 0;
            for (const auto& p : pets) {
                if (p.pos.r == r1 || p.pos.r == r2) pets_on_wall++;
            }
            // Pets on wall rows count as "middle" (they'll move away eventually)

            int area_above = (r1 - 1) * GRID_SIZE;
            int area_below = (GRID_SIZE - r2) * GRID_SIZE;

            // Count humans in each zone
            int h_above = 0, h_below = 0;
            for (const auto& h : humans) {
                if (h.pos.r < r1) h_above++;
                else if (h.pos.r > r2) h_below++;
            }

            // Score: average satisfaction across all M humans
            // Humans go to whichever side is bigger, or split optimally
            // Try putting all humans above
            double score_all_above = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
            // Try putting all humans below
            double score_all_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
            // Try splitting: half above, half below
            double score_split = 0.5 * (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above)
                               + 0.5 * (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);

            double best_sc = std::max({score_all_above, score_all_below, score_split});
            int side = 0; // above
            if (best_sc == score_all_below) side = 1; // below
            else if (best_sc == score_split) side = 2; // both

            // Wall feasibility (60 walls for dual horizontal)
            int nw = 2 * GRID_SIZE;
            double feasibility = std::min(1.0, (double)(M * 90) / nw);
            best_sc *= feasibility;

            // Penalty for pets on wall rows (harder to build)
            best_sc *= std::pow(0.95, pets_on_wall);

            if (best_sc > best_config.score) {
                best_config.score = best_sc;
                best_config.strat = DUAL_H;
                best_config.wall_pos1 = r1;
                best_config.wall_pos2 = r2;
                best_config.side = side;
                best_config.walls.clear();
                for (int c = 1; c <= GRID_SIZE; c++) {
                    best_config.walls.push_back({r1, c});
                    best_config.walls.push_back({r2, c});
                }
                if (side == 0) {
                    best_config.safe_r1 = 1; best_config.safe_r2 = r1 - 1;
                    best_config.safe_c1 = 1; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = area_above;
                    best_config.pets_in_safe = pets_above;
                } else if (side == 1) {
                    best_config.safe_r1 = r2 + 1; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_c1 = 1; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = area_below;
                    best_config.pets_in_safe = pets_below;
                } else {
                    // For split, target larger side
                    if (area_above >= area_below) {
                        best_config.safe_r1 = 1; best_config.safe_r2 = r1 - 1;
                    } else {
                        best_config.safe_r1 = r2 + 1; best_config.safe_r2 = GRID_SIZE;
                    }
                    best_config.safe_c1 = 1; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = std::max(area_above, area_below);
                    best_config.pets_in_safe = (area_above >= area_below) ? pets_above : pets_below;
                }
            }
        }
    }

    // Dual Vertical: walls at cols c1 and c2, pets between, humans left + right
    for (int c1 = 2; c1 <= 14; c1++) {
        for (int c2 = c1 + 3; c2 <= 29; c2++) {
            int pets_left = count_pets_in_cols(1, c1 - 1);
            int pets_right = count_pets_in_cols(c2 + 1, GRID_SIZE);
            int pets_on_wall = 0;
            for (const auto& p : pets) {
                if (p.pos.c == c1 || p.pos.c == c2) pets_on_wall++;
            }

            int area_left = GRID_SIZE * (c1 - 1);
            int area_right = GRID_SIZE * (GRID_SIZE - c2);

            double score_all_left = (double)area_left / 900.0 * std::pow(2.0, -(double)pets_left);
            double score_all_right = (double)area_right / 900.0 * std::pow(2.0, -(double)pets_right);
            double score_split = 0.5 * (double)area_left / 900.0 * std::pow(2.0, -(double)pets_left)
                               + 0.5 * (double)area_right / 900.0 * std::pow(2.0, -(double)pets_right);

            double best_sc = std::max({score_all_left, score_all_right, score_split});
            int side = 0;
            if (best_sc == score_all_right) side = 1;
            else if (best_sc == score_split) side = 2;

            int nw = 2 * GRID_SIZE;
            double feasibility = std::min(1.0, (double)(M * 90) / nw);
            best_sc *= feasibility;
            best_sc *= std::pow(0.95, pets_on_wall);

            if (best_sc > best_config.score) {
                best_config.score = best_sc;
                best_config.strat = DUAL_V;
                best_config.wall_pos1 = c1;
                best_config.wall_pos2 = c2;
                best_config.side = side;
                best_config.walls.clear();
                for (int r = 1; r <= GRID_SIZE; r++) {
                    best_config.walls.push_back({r, c1});
                    best_config.walls.push_back({r, c2});
                }
                if (side == 0) {
                    best_config.safe_r1 = 1; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_c1 = 1; best_config.safe_c2 = c1 - 1;
                    best_config.safe_area = area_left;
                    best_config.pets_in_safe = pets_left;
                } else if (side == 1) {
                    best_config.safe_r1 = 1; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_c1 = c2 + 1; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = area_right;
                    best_config.pets_in_safe = pets_right;
                } else {
                    if (area_left >= area_right) {
                        best_config.safe_c1 = 1; best_config.safe_c2 = c1 - 1;
                    } else {
                        best_config.safe_c1 = c2 + 1; best_config.safe_c2 = GRID_SIZE;
                    }
                    best_config.safe_r1 = 1; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_area = std::max(area_left, area_right);
                    best_config.pets_in_safe = (area_left >= area_right) ? pets_left : pets_right;
                }
            }
        }
    }

    // Single horizontal wall options (using one boundary)
    for (int r = 2; r <= 29; r++) {
        // Top safe zone: rows 1..r-1
        int pets_above = count_pets_in_rows(1, r - 1);
        int area_above = (r - 1) * GRID_SIZE;
        double sc = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
        int nw = GRID_SIZE;
        double feasibility = std::min(1.0, (double)(M * 90) / nw);
        sc *= feasibility;

        if (sc > best_config.score) {
            best_config.score = sc;
            best_config.strat = SINGLE_H_TOP;
            best_config.wall_pos1 = r;
            best_config.wall_pos2 = r;
            best_config.side = 0;
            best_config.walls.clear();
            for (int c = 1; c <= GRID_SIZE; c++) best_config.walls.push_back({r, c});
            best_config.safe_r1 = 1; best_config.safe_r2 = r - 1;
            best_config.safe_c1 = 1; best_config.safe_c2 = GRID_SIZE;
            best_config.safe_area = area_above;
            best_config.pets_in_safe = pets_above;
        }

        // Bottom safe zone: rows r+1..30
        int pets_below = count_pets_in_rows(r + 1, GRID_SIZE);
        int area_below = (GRID_SIZE - r) * GRID_SIZE;
        sc = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
        sc *= feasibility;

        if (sc > best_config.score) {
            best_config.score = sc;
            best_config.strat = SINGLE_H_BOT;
            best_config.wall_pos1 = r;
            best_config.wall_pos2 = r;
            best_config.side = 1;
            best_config.walls.clear();
            for (int c = 1; c <= GRID_SIZE; c++) best_config.walls.push_back({r, c});
            best_config.safe_r1 = r + 1; best_config.safe_r2 = GRID_SIZE;
            best_config.safe_c1 = 1; best_config.safe_c2 = GRID_SIZE;
            best_config.safe_area = area_below;
            best_config.pets_in_safe = pets_below;
        }
    }

    // Single vertical wall options
    for (int c = 2; c <= 29; c++) {
        int pets_left = count_pets_in_cols(1, c - 1);
        int area_left = GRID_SIZE * (c - 1);
        double sc = (double)area_left / 900.0 * std::pow(2.0, -(double)pets_left);
        int nw = GRID_SIZE;
        double feasibility = std::min(1.0, (double)(M * 90) / nw);
        sc *= feasibility;

        if (sc > best_config.score) {
            best_config.score = sc;
            best_config.strat = SINGLE_V_LEFT;
            best_config.wall_pos1 = c;
            best_config.wall_pos2 = c;
            best_config.side = 0;
            best_config.walls.clear();
            for (int r = 1; r <= GRID_SIZE; r++) best_config.walls.push_back({r, c});
            best_config.safe_r1 = 1; best_config.safe_r2 = GRID_SIZE;
            best_config.safe_c1 = 1; best_config.safe_c2 = c - 1;
            best_config.safe_area = area_left;
            best_config.pets_in_safe = pets_left;
        }

        int pets_right = count_pets_in_cols(c + 1, GRID_SIZE);
        int area_right = GRID_SIZE * (GRID_SIZE - c);
        sc = (double)area_right / 900.0 * std::pow(2.0, -(double)pets_right);
        sc *= feasibility;

        if (sc > best_config.score) {
            best_config.score = sc;
            best_config.strat = SINGLE_V_RIGHT;
            best_config.wall_pos1 = c;
            best_config.wall_pos2 = c;
            best_config.side = 1;
            best_config.walls.clear();
            for (int r = 1; r <= GRID_SIZE; r++) best_config.walls.push_back({r, c});
            best_config.safe_r1 = 1; best_config.safe_r2 = GRID_SIZE;
            best_config.safe_c1 = c + 1; best_config.safe_c2 = GRID_SIZE;
            best_config.safe_area = area_right;
            best_config.pets_in_safe = pets_right;
        }
    }

    // Corner rectangles (using 2 boundaries + 2 walls)
    for (int h = 5; h <= 25; h += 1) {
        for (int w = 5; w <= 25; w += 1) {
            // Top-left corner: rows 1..h, cols 1..w, walls at row h+1 (cols 1..w) and col w+1 (rows 1..h)
            if (h + 1 <= GRID_SIZE && w + 1 <= GRID_SIZE) {
                int pets_in = 0;
                for (const auto& p : pets)
                    if (p.pos.r >= 1 && p.pos.r <= h && p.pos.c >= 1 && p.pos.c <= w) pets_in++;
                int area = h * w;
                int nw = w + h; // wall cells needed
                double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                double feasibility = std::min(1.0, (double)(M * 90) / nw);
                sc *= feasibility;

                if (sc > best_config.score) {
                    best_config.score = sc;
                    best_config.strat = SINGLE_H_TOP; // reuse
                    best_config.walls.clear();
                    for (int c = 1; c <= w; c++) best_config.walls.push_back({h + 1, c});
                    for (int r = 1; r <= h; r++) best_config.walls.push_back({r, w + 1});
                    best_config.safe_r1 = 1; best_config.safe_r2 = h;
                    best_config.safe_c1 = 1; best_config.safe_c2 = w;
                    best_config.safe_area = area;
                    best_config.pets_in_safe = pets_in;
                    best_config.side = 0;
                }
            }

            // Top-right corner
            if (h + 1 <= GRID_SIZE && GRID_SIZE - w >= 1) {
                int cs = GRID_SIZE - w + 1;
                int pets_in = 0;
                for (const auto& p : pets)
                    if (p.pos.r >= 1 && p.pos.r <= h && p.pos.c >= cs && p.pos.c <= GRID_SIZE) pets_in++;
                int area = h * w;
                int nw = w + h;
                double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                double feasibility = std::min(1.0, (double)(M * 90) / nw);
                sc *= feasibility;

                if (sc > best_config.score) {
                    best_config.score = sc;
                    best_config.strat = SINGLE_H_TOP;
                    best_config.walls.clear();
                    for (int c = cs; c <= GRID_SIZE; c++) best_config.walls.push_back({h + 1, c});
                    for (int r = 1; r <= h; r++) best_config.walls.push_back({r, cs - 1});
                    best_config.safe_r1 = 1; best_config.safe_r2 = h;
                    best_config.safe_c1 = cs; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = area;
                    best_config.pets_in_safe = pets_in;
                    best_config.side = 0;
                }
            }

            // Bottom-left corner
            if (GRID_SIZE - h >= 1 && w + 1 <= GRID_SIZE) {
                int rs = GRID_SIZE - h + 1;
                int pets_in = 0;
                for (const auto& p : pets)
                    if (p.pos.r >= rs && p.pos.r <= GRID_SIZE && p.pos.c >= 1 && p.pos.c <= w) pets_in++;
                int area = h * w;
                int nw = w + h;
                double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                double feasibility = std::min(1.0, (double)(M * 90) / nw);
                sc *= feasibility;

                if (sc > best_config.score) {
                    best_config.score = sc;
                    best_config.strat = SINGLE_H_BOT;
                    best_config.walls.clear();
                    for (int c = 1; c <= w; c++) best_config.walls.push_back({rs - 1, c});
                    for (int r = rs; r <= GRID_SIZE; r++) best_config.walls.push_back({r, w + 1});
                    best_config.safe_r1 = rs; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_c1 = 1; best_config.safe_c2 = w;
                    best_config.safe_area = area;
                    best_config.pets_in_safe = pets_in;
                    best_config.side = 1;
                }
            }

            // Bottom-right corner
            if (GRID_SIZE - h >= 1 && GRID_SIZE - w >= 1) {
                int rs = GRID_SIZE - h + 1;
                int cs = GRID_SIZE - w + 1;
                int pets_in = 0;
                for (const auto& p : pets)
                    if (p.pos.r >= rs && p.pos.r <= GRID_SIZE && p.pos.c >= cs && p.pos.c <= GRID_SIZE) pets_in++;
                int area = h * w;
                int nw = w + h;
                double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
                double feasibility = std::min(1.0, (double)(M * 90) / nw);
                sc *= feasibility;

                if (sc > best_config.score) {
                    best_config.score = sc;
                    best_config.strat = SINGLE_H_BOT;
                    best_config.walls.clear();
                    for (int c = cs; c <= GRID_SIZE; c++) best_config.walls.push_back({rs - 1, c});
                    for (int r = rs; r <= GRID_SIZE; r++) best_config.walls.push_back({r, cs - 1});
                    best_config.safe_r1 = rs; best_config.safe_r2 = GRID_SIZE;
                    best_config.safe_c1 = cs; best_config.safe_c2 = GRID_SIZE;
                    best_config.safe_area = area;
                    best_config.pets_in_safe = pets_in;
                    best_config.side = 1;
                }
            }
        }
    }

    std::vector<Point> walls_needed = best_config.walls;
    Point safe_center = {(best_config.safe_r1 + best_config.safe_r2) / 2,
                         (best_config.safe_c1 + best_config.safe_c2) / 2};

    // Phase-based execution
    // Phase 1: Move humans to safe zone (first ~50 turns or until in position)
    // Phase 2: Build walls
    // Phase 3: Spread out in safe zone

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls
        walls_needed.erase(
            std::remove_if(walls_needed.begin(), walls_needed.end(),
                [](const Point& p) { return wall_grid[p.r][p.c]; }),
            walls_needed.end()
        );

        bool building_done = walls_needed.empty();

        if (!building_done) {
            // Check which humans are in the safe zone already
            auto in_safe = [&](Point p) {
                return p.r >= best_config.safe_r1 && p.r <= best_config.safe_r2 &&
                       p.c >= best_config.safe_c1 && p.c <= best_config.safe_c2;
            };

            // Assign walls to humans (greedy closest unassigned)
            std::vector<bool> wall_taken(walls_needed.size(), false);
            std::vector<int> assignment(M, -1);

            // Priority: humans closest to any remaining wall
            std::vector<std::pair<int, int>> human_min_dist(M);
            for (int i = 0; i < M; i++) {
                int min_d = INF;
                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    int d = std::abs(humans[i].pos.r - walls_needed[j].r) + std::abs(humans[i].pos.c - walls_needed[j].c);
                    min_d = std::min(min_d, d);
                }
                human_min_dist[i] = {min_d, i};
            }
            std::sort(human_min_dist.begin(), human_min_dist.end());

            for (auto& [dist, i] : human_min_dist) {
                Point hp = humans[i].pos;
                int best_idx = -1;
                int best_dist = INF;

                // Prioritize walls we can build RIGHT NOW
                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    if (wall_taken[j]) continue;
                    Point wc = walls_needed[j];
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand == hp && can_build_wall(wc, i)) {
                            best_idx = j;
                            best_dist = 0;
                            goto found_wall;
                        }
                    }
                }

                // Find closest wall
                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    if (wall_taken[j]) continue;
                    Point wc = walls_needed[j];
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int dd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (dd < best_dist) {
                            best_dist = dd;
                            best_idx = j;
                        }
                    }
                }

                found_wall:
                if (best_idx != -1) {
                    assignment[i] = best_idx;
                    wall_taken[best_idx] = true;
                }
            }

            // Execute
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                if (assignment[i] == -1) {
                    // Move toward safe zone
                    actions[i] = bfs_move_toward(hp, safe_center);
                    continue;
                }

                Point wc = walls_needed[assignment[i]];

                // Try to build
                bool built = false;
                for (int d = 0; d < 4; d++) {
                    Point target = {hp.r + DIRS[d].r, hp.c + DIRS[d].c};
                    if (target == wc && can_build_wall(wc, i)) {
                        bool tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wc) { tent = true; break; }
                        }
                        if (!tent) {
                            actions[i] = DIR_BUILD[d];
                            tentative_walls.push_back(wc);
                            built = true;
                            break;
                        }
                    }
                }

                if (!built) {
                    // Move toward best stand position
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int sd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move_toward(hp, best_stand);
                    }
                }
            }
        } else {
            // Walls done - move humans to spread out in safe zone
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                int spread_c = best_config.safe_c1 + 1 +
                    (i * std::max(0, best_config.safe_c2 - best_config.safe_c1 - 2)) / std::max(1, M - 1);
                int spread_r = best_config.safe_r1 + 1 +
                    (i * std::max(0, best_config.safe_r2 - best_config.safe_r1 - 2)) / std::max(1, M - 1);
                Point target = {spread_r, spread_c};
                target.r = std::max(best_config.safe_r1, std::min(best_config.safe_r2, target.r));
                target.c = std::max(best_config.safe_c1, std::min(best_config.safe_c2, target.c));
                actions[i] = bfs_move_toward(hp, target);
            }
        }

        // Validate all actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall_grid[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Cancel moves to tentatively walled cells
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                for (const auto& tw : tentative_walls) {
                    if (np == tw) {
                        actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall_grid[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (np.r >= 1 && np.r <= GRID_SIZE && np.c >= 1 && np.c <= GRID_SIZE && !wall_grid[np.r][np.c]) {
                    humans[i].pos = np;
                }
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
