                        bool on_safe = (sr >= safe_r_min && sr <= safe_r_max);
                        if (on_safe) sd -= 1; // slight preference
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = {sr, sc};
                        }
                    }
                    if (best_stand.r != -1) {
