        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_BUILD[dd]) { d = dd; break; }
                Point wp = {hpos.r + DR[d], hpos.c + DC[d]};
                if (!can_build_wall(wp)) actions[i] = '.';
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
