                         (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below)) ? 0 : 1;
        }
    }

    bool single_wall = (best_r1 == best_r2);

    // Determine safe zone
    int safe_r_min, safe_r_max;
    if (best_side == 0) {
        safe_r_min = 1;
        safe_r_max = best_r1 - 1;
    } else if (best_side == 1) {
        safe_r_min = best_r2 + 1;
        safe_r_max = GRID_SIZE;
    } else {
        // Split: primary target is the larger side
        int area_above = (best_r1 - 1) * GRID_SIZE;
        int area_below = (GRID_SIZE - best_r2) * GRID_SIZE;
        if (area_above >= area_below) {
            safe_r_min = 1; safe_r_max = best_r1 - 1;
        } else {
            safe_r_min = best_r2 + 1; safe_r_max = GRID_SIZE;
        }
    }

    // Generate walls to build, ordered from edges inward (critical for blocking)
    std::vector<Point> wall1_cells, wall2_cells;
    // Wall 1 (top wall at best_r1)
    for (int c = 1; c <= GRID_SIZE; c++) wall1_cells.push_back({best_r1, c});
    // Sort from edges inward
    std::sort(wall1_cells.begin(), wall1_cells.end(), [](const Point& a, const Point& b) {
        int da = std::min(a.c, GRID_SIZE + 1 - a.c);
        int db = std::min(b.c, GRID_SIZE + 1 - b.c);
        return da > db; // edges first (they have larger min-dist-to-center)
    });
    // Actually we want edges first: c=1 and c=30 first, then c=2 and c=29, etc.
    wall1_cells.clear();
    for (int offset = 0; offset < 15; offset++) {
        wall1_cells.push_back({best_r1, 1 + offset});
        wall1_cells.push_back({best_r1, GRID_SIZE - offset});
    }

    if (!single_wall) {
        for (int offset = 0; offset < 15; offset++) {
            wall2_cells.push_back({best_r2, 1 + offset});
            wall2_cells.push_back({best_r2, GRID_SIZE - offset});
        }
    }

    // Combine: interleave wall1 and wall2
    std::vector<Point> all_walls;
    int i1 = 0, i2 = 0;
    while (i1 < (int)wall1_cells.size() || i2 < (int)wall2_cells.size()) {
        if (i1 < (int)wall1_cells.size()) all_walls.push_back(wall1_cells[i1++]);
        if (i2 < (int)wall2_cells.size()) all_walls.push_back(wall2_cells[i2++]);
    }

    // Remove duplicates (for single wall where best_r1==best_r2)
    if (single_wall) {
        all_walls = wall1_cells;
    }

    // Phase management
    // Phase 0: Move humans toward safe side (turns 0..move_phase_end)
    // Phase 1: Build walls (turns move_phase_end..)
    // Phase 2: Spread in safe zone (after walls done)

    int move_phase_turns = single_wall ? 20 : 30; // time budget for moving

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls from list
        all_walls.erase(
            std::remove_if(all_walls.begin(), all_walls.end(),
                [](const Point& p) { return wall_grid[p.r][p.c]; }),
            all_walls.end()
        );

        bool walls_done = all_walls.empty();

        if (turn < move_phase_turns && !walls_done) {
            // Phase 0: Move humans toward safe side
            // But if a human is already adjacent to a needed wall, let them build
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                bool built = false;

                // Check if we can opportunistically build a wall
                for (int d = 0; d < 4; d++) {
                    int nr = hp.r + DR[d], nc = hp.c + DC[d];
                    if (nr < 1 || nr > GRID_SIZE || nc < 1 || nc > GRID_SIZE) continue;
                    Point wp = {nr, nc};
                    // Is this a needed wall?
                    bool needed = false;
                    for (const auto& w : all_walls) {
                        if (w == wp) { needed = true; break; }
                    }
                    if (needed && can_build_wall(wp)) {
                        bool tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wp) { tent = true; break; }
                        }
                        if (!tent) {
                            actions[i] = DIR_BUILD[d];
                            tentative_walls.push_back(wp);
                            built = true;
                            break;
                        }
                    }
                }

                if (!built) {
                    // Move toward safe zone center
                    int target_r = (safe_r_min + safe_r_max) / 2;
                    int target_c = 1 + (i * (GRID_SIZE - 1)) / std::max(1, M - 1);
                    actions[i] = get_move_toward(hp, {target_r, target_c});
                }
            }
        } else if (!walls_done) {
            // Phase 1: Build walls
            // Assign walls to humans greedily
            std::vector<bool> wall_taken(all_walls.size(), false);
            std::vector<int> assignment(M, -1);

            // Each human finds closest wall to build
            for (int pass = 0; pass < M; pass++) {
                int best_human = -1, best_wall = -1, best_dist = INF;

                for (int i = 0; i < M; i++) {
                    if (assignment[i] != -1) continue;
                    Point hp = humans[i].pos;

                    for (int j = 0; j < (int)all_walls.size(); j++) {
                        if (wall_taken[j]) continue;
                        Point wc = all_walls[j];

                        // Check if can build now (distance 0)
                        for (int d = 0; d < 4; d++) {
                            int sr = wc.r + DR[d], sc = wc.c + DC[d];
                            if (sr == hp.r && sc == hp.c) {
                                if (can_build_wall(wc)) {
                                    if (0 < best_dist) {
                                        best_dist = 0;
                                        best_human = i;
                                        best_wall = j;
                                    }
                                }
                            }
                        }

                        // Manhattan distance to nearest build position
                        if (best_dist > 0) {
                            for (int d = 0; d < 4; d++) {
                                int sr = wc.r + DR[d], sc = wc.c + DC[d];
                                if (sr < 1 || sr > GRID_SIZE || sc < 1 || sc > GRID_SIZE) continue;
                                if (wall_grid[sr][sc]) continue;
                                int dist = std::abs(hp.r - sr) + std::abs(hp.c - sc);
                                if (dist < best_dist) {
                                    best_dist = dist;
                                    best_human = i;
                                    best_wall = j;
                                }
                            }
                        }
                    }
                }

                if (best_human == -1) break;
                assignment[best_human] = best_wall;
                wall_taken[best_wall] = true;
            }

            // Execute
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                if (assignment[i] == -1) {
                    // No wall assigned - move toward safe zone
                    int target_r = (safe_r_min + safe_r_max) / 2;
                    actions[i] = get_move_toward(hp, {target_r, GRID_SIZE / 2});
                    continue;
                }

                Point wc = all_walls[assignment[i]];

                // Try to build
                bool built = false;
                for (int d = 0; d < 4; d++) {
                    int nr = hp.r + DR[d], nc = hp.c + DC[d];
                    if (nr == wc.r && nc == wc.c && can_build_wall(wc)) {
                        bool tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wc) { tent = true; break; }
                        }
                        if (!tent) {
                            actions[i] = DIR_BUILD[d];
                            tentative_walls.push_back(wc);
                            built = true;
                            break;
                        }
                    }
                }

                if (!built) {
                    // Move toward best build position (prefer safe side)
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wc.r + DR[d], sc = wc.c + DC[d];
                        if (sr < 1 || sr > GRID_SIZE || sc < 1 || sc > GRID_SIZE) continue;
                        if (wall_grid[sr][sc]) continue;
                        int sd = std::abs(hp.r - sr) + std::abs(hp.c - sc);
                        // Prefer standing on safe side
                        bool on_safe = (sr >= safe_r_min && sr <= safe_r_max);
                        if (on_safe) sd -= 1; // slight preference
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = {sr, sc};
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = get_move_toward(hp, best_stand);
                    }
                }
            }
        } else {
            // Phase 2: Walls done, move humans to safe zone
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                bool in_safe = (hp.r >= safe_r_min && hp.r <= safe_r_max);
                if (!in_safe) {
                    int target_r = (safe_r_min + safe_r_max) / 2;
                    actions[i] = get_move_toward(hp, {target_r, hp.c});
                } else {
                    // Spread out
                    int target_c = 1 + (i * (GRID_SIZE - 1)) / std::max(1, M - 1);
                    int target_r = (safe_r_min + safe_r_max) / 2;
                    Point target = {target_r, target_c};
                    if (hp != target) {
                        actions[i] = get_move_toward(hp, target);
                    }
                }
            }
        }

        // Validate
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_BUILD[dd]) { d = dd; break; }
                Point wp = {hpos.r + DR[d], hpos.c + DC[d]};
                if (!can_build_wall(wp)) actions[i] = '.';
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_MOVE[dd]) { d = dd; break; }
                int nr = hpos.r + DR[d], nc = hpos.c + DC[d];
                if (nr < 1 || nr > GRID_SIZE || nc < 1 || nc > GRID_SIZE || wall_grid[nr][nc])
                    actions[i] = '.';
            }
        }

        // Cancel moves to tentative walls
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_MOVE[dd]) { d = dd; break; }
                Point np = {humans[i].pos.r + DR[d], humans[i].pos.c + DC[d]};
                for (const auto& tw : tentative_walls) {
                    if (np == tw) { actions[i] = '.'; break; }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_BUILD[dd]) { d = dd; break; }
                int wr = humans[i].pos.r + DR[d], wc = humans[i].pos.c + DC[d];
                if (wr >= 1 && wr <= GRID_SIZE && wc >= 1 && wc <= GRID_SIZE)
                    wall_grid[wr][wc] = true;
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_MOVE[dd]) { d = dd; break; }
                int nr = humans[i].pos.r + DR[d], nc = humans[i].pos.c + DC[d];
                if (nr >= 1 && nr <= GRID_SIZE && nc >= 1 && nc <= GRID_SIZE && !wall_grid[nr][nc])
                    humans[i].pos = {nr, nc};
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DR[d];
                        pets[i].pos.c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
