# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1000000;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];
int bfs_dist_grid[31][31];

void compute_bfs_from(Point target) {
    memset(bfs_dist_grid, -1, sizeof(bfs_dist_grid));
    std::queue<Point> q;
    bfs_dist_grid[target.r][target.c] = 0;
    q.push(target);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (nr < 1 || nr > GRID_SIZE || nc < 1 || nc > GRID_SIZE) continue;
            if (wall_grid[nr][nc]) continue;
            if (bfs_dist_grid[nr][nc] != -1) continue;
            bfs_dist_grid[nr][nc] = bfs_dist_grid[cur.r][cur.c] + 1;
            q.push({nr, nc});
        }
    }
}

char get_move_toward(Point start, Point target) {
    if (start == target) return '.';
    compute_bfs_from(target);
    if (bfs_dist_grid[start.r][start.c] == -1) return '.';
    int best_d = -1, best_dist = bfs_dist_grid[start.r][start.c];
    for (int d = 0; d < 4; d++) {
        int nr = start.r + DR[d], nc = start.c + DC[d];
        if (nr < 1 || nr > GRID_SIZE || nc < 1 || nc > GRID_SIZE) continue;
        if (wall_grid[nr][nc]) continue;
        if (bfs_dist_grid[nr][nc] < best_dist) {
            best_dist = bfs_dist_grid[nr][nc];
            best_d = d;
        }
    }
    return best_d >= 0 ? DIR_MOVE[best_d] : '.';
}

bool can_build_wall(Point pos) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall_grid[pos.r][pos.c]) return false;
    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].pos == pos) return false;
    }
    return true;
}

struct Zone {
    int r1, r2, c1, c2;  // safe zone bounds
    std::vector<Point> walls;
    int area;
    int pets_init;
    double score_est;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall_grid, false, sizeof(wall_grid));

    // Strategy: Assign each human (or group of humans) to build their own
    // corner/edge pocket. Each human independently builds a small rectangle
    // using grid boundaries. Multiple humans can share the same pocket.
    //
    // Key advantage: each pocket needs only 10-20 walls (vs 60 for dual horizontal)
    // so construction finishes in 10-30 turns, before pets wander in.

    // Generate candidate pockets (L-shaped from corners + edge strips)
    std::vector<Zone> candidates;

    // Corner pockets of various sizes
    for (int size = 6; size <= 20; size++) {
        // Top-left: rows 1..size, cols 1..size, walls at row size+1 (c=1..size) + col size+1 (r=1..size)
        if (size + 1 <= GRID_SIZE) {
            Zone z;
            z.r1 = 1; z.r2 = size; z.c1 = 1; z.c2 = size;
            z.area = size * size;
            z.pets_init = 0;
            for (const auto& p : pets)
                if (p.pos.r >= z.r1 && p.pos.r <= z.r2 && p.pos.c >= z.c1 && p.pos.c <= z.c2)
                    z.pets_init++;
            for (int c = 1; c <= size; c++) z.walls.push_back({size + 1, c});
            for (int r = 1; r <= size; r++) z.walls.push_back({r, size + 1});
            z.score_est = (double)z.area / 900.0 * std::pow(2.0, -(double)z.pets_init);
            candidates.push_back(z);
        }

        // Top-right
        if (size + 1 <= GRID_SIZE) {
            Zone z;
            z.r1 = 1; z.r2 = size; z.c1 = GRID_SIZE - size + 1; z.c2 = GRID_SIZE;
            z.area = size * size;
            z.pets_init = 0;
            for (const auto& p : pets)
                if (p.pos.r >= z.r1 && p.pos.r <= z.r2 && p.pos.c >= z.c1 && p.pos.c <= z.c2)
                    z.pets_init++;
            for (int c = z.c1; c <= GRID_SIZE; c++) z.walls.push_back({size + 1, c});
            for (int r = 1; r <= size; r++) z.walls.push_back({r, z.c1 - 1});
            z.score_est = (double)z.area / 900.0 * std::pow(2.0, -(double)z.pets_init);
            candidates.push_back(z);
        }

        // Bottom-left
        if (GRID_SIZE - size >= 1) {
            Zone z;
            z.r1 = GRID_SIZE - size + 1; z.r2 = GRID_SIZE; z.c1 = 1; z.c2 = size;
            z.area = size * size;
            z.pets_init = 0;
            for (const auto& p : pets)
                if (p.pos.r >= z.r1 && p.pos.r <= z.r2 && p.pos.c >= z.c1 && p.pos.c <= z.c2)
                    z.pets_init++;
            for (int c = 1; c <= size; c++) z.walls.push_back({z.r1 - 1, c});
            for (int r = z.r1; r <= GRID_SIZE; r++) z.walls.push_back({r, size + 1});
            z.score_est = (double)z.area / 900.0 * std::pow(2.0, -(double)z.pets_init);
            candidates.push_back(z);
        }

        // Bottom-right
        if (GRID_SIZE - size >= 1) {
            Zone z;
            z.r1 = GRID_SIZE - size + 1; z.r2 = GRID_SIZE; z.c1 = GRID_SIZE - size + 1; z.c2 = GRID_SIZE;
            z.area = size * size;
            z.pets_init = 0;
            for (const auto& p : pets)
                if (p.pos.r >= z.r1 && p.pos.r <= z.r2 && p.pos.c >= z.c1 && p.pos.c <= z.c2)
                    z.pets_init++;
            for (int c = z.c1; c <= GRID_SIZE; c++) z.walls.push_back({z.r1 - 1, c});
            for (int r = z.r1; r <= GRID_SIZE; r++) z.walls.push_back({r, z.c1 - 1});
            z.score_est = (double)z.area / 900.0 * std::pow(2.0, -(double)z.pets_init);
            candidates.push_back(z);
        }
    }

    // Also add non-square rectangles using boundary + one wall
    for (int h = 5; h <= 20; h++) {
        for (int w = 5; w <= 20; w++) {
            if (h == w) continue; // already covered
            if (h + w > M * 50) continue; // too many walls

            // Top-left
            if (h + 1 <= GRID_SIZE && w + 1 <= GRID_SIZE) {
                Zone z;
                z.r1 = 1; z.r2 = h; z.c1 = 1; z.c2 = w;
                z.area = h * w;
                z.pets_init = 0;
                for (const auto& p : pets)
                    if (p.pos.r >= 1 && p.pos.r <= h && p.pos.c >= 1 && p.pos.c <= w)
                        z.pets_init++;
                for (int c = 1; c <= w; c++) z.walls.push_back({h + 1, c});
                for (int r = 1; r <= h; r++) z.walls.push_back({r, w + 1});
                z.score_est = (double)z.area / 900.0 * std::pow(2.0, -(double)z.pets_init);
                candidates.push_back(z);
            }
        }
    }

    // Sort candidates by score/walls_count ratio (efficiency)
    std::sort(candidates.begin(), candidates.end(), [](const Zone& a, const Zone& b) {
        return a.score_est > b.score_est;
    });

    // Strategy selection:
    // Option A: Put ALL humans in the single best pocket
    // Option B: Split humans across 2 best non-overlapping pockets

    // Option A: best single pocket, all humans share it
    Zone best_single = candidates[0];
    double score_a = best_single.score_est;
    // Penalty: wall count vs human capacity
    double build_time_a = (double)best_single.walls.size() / M;
    if (build_time_a > 100) score_a *= 0.5; // too slow

    // Option B: find 2 non-overlapping pockets
