                int wr = humans[i].pos.r + DR[d], wc_c = humans[i].pos.c + DC[d];
                if (wr >= 1 && wr <= GRID_SIZE && wc_c >= 1 && wc_c <= GRID_SIZE)
                    wall_grid[wr][wc_c] = true;
            }
