        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) if (a == DIR_MOVE[dd]) { d = dd; break; }
                int nr = humans[i].pos.r + DR[d], nc = humans[i].pos.c + DC[d];
                if (nr >= 1 && nr <= GRID_SIZE && nc >= 1 && nc <= GRID_SIZE && !wall_grid[nr][nc])
                    humans[i].pos = {nr, nc};
            }
        }

        // Read pet moves
        for (int i = 0; i < N; i++) {
            std::string pmove;
            std::cin >> pmove;
            if (pmove == ".") continue;
            for (char c : pmove) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DR[d];
                        pets[i].pos.c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
