# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1000000;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];

int bfs_dist_buf[31][31];
Point bfs_parent_buf[31][31];

char bfs_move(Point start, Point target) {
    if (start == target) return '.';

    memset(bfs_dist_buf, -1, sizeof(bfs_dist_buf));
    std::queue<Point> q;
    bfs_dist_buf[start.r][start.c] = 0;
    bfs_parent_buf[start.r][start.c] = {-1, -1};
    q.push(start);

    while (!q.empty()) {
        Point cur = q.front(); q.pop();

        for (int d = 0; d < 4; d++) {
            Point np = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE) continue;
            if (wall_grid[np.r][np.c]) continue;
            if (bfs_dist_buf[np.r][np.c] != -1) continue;

            bfs_dist_buf[np.r][np.c] = bfs_dist_buf[cur.r][cur.c] + 1;
            bfs_parent_buf[np.r][np.c] = cur;
            q.push(np);

            if (np == target) {
                Point step = np;
                while (!(bfs_parent_buf[step.r][step.c] == start)) {
                    step = bfs_parent_buf[step.r][step.c];
                }
                for (int i = 0; i < 4; i++) {
                    if (start.r + DIRS[i].r == step.r && start.c + DIRS[i].c == step.c) {
                        return DIR_MOVE[i];
                    }
                }
                return '.';
            }
        }
    }
    return '.';
}

bool can_build_wall(Point pos, int builder_id) {
    if (pos.r < 1 || pos.r > GRID_SIZE || pos.c < 1 || pos.c > GRID_SIZE) return false;
    if (wall_grid[pos.r][pos.c]) return false;

    for (const auto& pet : pets) {
        if (pet.pos == pos) return false;
        if (std::abs(pet.pos.r - pos.r) + std::abs(pet.pos.c - pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (i == builder_id) continue;
        if (humans[i].pos == pos) return false;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(wall_grid, false, sizeof(wall_grid));

    // Evaluate rectangular safe zones
    struct Option {
        int r1, r2, c1, c2;
        std::vector<Point> walls;
        int n_pets;
        int area;
        double score;
    };

    std::vector<Option> options;

    // Single horizontal walls
    for (int w = 3; w <= GRID_SIZE - 2; w++) {
        // Top: [1..w-1] x [1..30]
        int pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r <= w - 1) pets_in++;
        }
        int area = (w - 1) * GRID_SIZE;
        double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        std::vector<Point> ws;
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({1, w - 1, 1, GRID_SIZE, ws, pets_in, area, sc});

        // Bottom: [w+1..30] x [1..30]
        pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= w + 1) pets_in++;
        }
        area = (GRID_SIZE - w) * GRID_SIZE;
        sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        ws.clear();
        for (int c = 1; c <= GRID_SIZE; c++) ws.push_back({w, c});
        options.push_back({w + 1, GRID_SIZE, 1, GRID_SIZE, ws, pets_in, area, sc});
    }

    // Corner rectangles - only test reasonable sizes
    auto add_corner = [&](int r1, int r2, int c1, int c2, std::vector<Point> ws) {
        int pets_in = 0;
        for (const auto& pet : pets) {
            if (pet.pos.r >= r1 && pet.pos.r <= r2 && pet.pos.c >= c1 && pet.pos.c <= c2) pets_in++;
        }
        int area = (r2 - r1 + 1) * (c2 - c1 + 1);
        double sc = (double)area / 900.0 * std::pow(2.0, -(double)pets_in);
        options.push_back({r1, r2, c1, c2, ws, pets_in, area, sc});
    };

    for (int h = 5; h <= 22; h += 2) {
        for (int w = 5; w <= 22; w += 2) {
            // Top-left: [1..h] x [1..w]
            if (h + 1 <= GRID_SIZE && w + 1 <= GRID_SIZE) {
                std::vector<Point> ws;
                for (int c = 1; c <= w; c++) ws.push_back({h + 1, c});
                for (int r = 1; r <= h; r++) ws.push_back({r, w + 1});
                add_corner(1, h, 1, w, ws);
            }

            // Top-right: [1..h] x [30-w+1..30]
            {
                int cs = GRID_SIZE - w + 1;
                int cw = cs - 1;
                if (h + 1 <= GRID_SIZE && cw >= 1) {
                    std::vector<Point> ws;
                    for (int c = cs; c <= GRID_SIZE; c++) ws.push_back({h + 1, c});
                    for (int r = 1; r <= h; r++) ws.push_back({r, cw});
                    add_corner(1, h, cs, GRID_SIZE, ws);
                }
            }

            // Bottom-left: [30-h+1..30] x [1..w]
            {
                int rs = GRID_SIZE - h + 1;
                int rw = rs - 1;
                if (rw >= 1 && w + 1 <= GRID_SIZE) {
                    std::vector<Point> ws;
                    for (int c = 1; c <= w; c++) ws.push_back({rw, c});
                    for (int r = rs; r <= GRID_SIZE; r++) ws.push_back({r, w + 1});
                    add_corner(rs, GRID_SIZE, 1, w, ws);
                }
            }

            // Bottom-right: [30-h+1..30] x [30-w+1..30]
            {
                int rs = GRID_SIZE - h + 1;
                int rw = rs - 1;
                int cs = GRID_SIZE - w + 1;
                int cw = cs - 1;
                if (rw >= 1 && cw >= 1) {
                    std::vector<Point> ws;
                    for (int c = cs; c <= GRID_SIZE; c++) ws.push_back({rw, c});
                    for (int r = rs; r <= GRID_SIZE; r++) ws.push_back({r, cw});
                    add_corner(rs, GRID_SIZE, cs, GRID_SIZE, ws);
                }
            }
        }
    }

    // Feasibility penalty
    for (auto& opt : options) {
        int nw = opt.walls.size();
        double feasibility = 1.0;
        int max_walls = M * 80;
        if (nw > max_walls) {
            feasibility = (double)max_walls / nw;
        }
        opt.score *= feasibility;
    }

    std::sort(options.begin(), options.end(), [](const Option& a, const Option& b) {
        return a.score > b.score;
    });

    auto best = options[0];

    int target_r1 = best.r1, target_r2 = best.r2;
    int target_c1 = best.c1, target_c2 = best.c2;
    std::vector<Point> walls_needed = best.walls;
    Point center_safe = {(target_r1 + target_r2) / 2, (target_c1 + target_c2) / 2};

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> tentative_walls;

        // Remove completed walls
        walls_needed.erase(
            std::remove_if(walls_needed.begin(), walls_needed.end(),
                [](const Point& p) { return wall_grid[p.r][p.c]; }),
            walls_needed.end()
        );

        bool building_done = walls_needed.empty();

        if (!building_done) {
            // Assign walls to humans greedily
            std::vector<bool> wall_taken(walls_needed.size(), false);
            std::vector<int> assignment(M, -1);

            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                int best_idx = -1;
                int best_dist = INF;

                for (int j = 0; j < (int)walls_needed.size(); j++) {
                    if (wall_taken[j]) continue;
                    Point wc = walls_needed[j];

                    // Check if adjacent (distance 0 = can build now)
                    bool adjacent = false;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand == hp) { adjacent = true; break; }
                    }
                    if (adjacent) {
                        best_idx = j;
                        best_dist = 0;
                        break;
                    }

                    // Manhattan distance to nearest stand position
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int dist = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (dist < best_dist) {
                            best_dist = dist;
                            best_idx = j;
                        }
                    }
                }

                if (best_idx != -1) {
                    assignment[i] = best_idx;
                    wall_taken[best_idx] = true;
                }
            }

            // Execute
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;

                if (assignment[i] == -1) {
                    actions[i] = bfs_move(hp, center_safe);
                    continue;
                }

                Point wc = walls_needed[assignment[i]];

                // Check if adjacent and can build
                bool built = false;
                for (int d = 0; d < 4; d++) {
                    Point target = {hp.r + DIRS[d].r, hp.c + DIRS[d].c};
                    if (target == wc && can_build_wall(wc, i)) {
                        bool tent = false;
                        for (const auto& tw : tentative_walls) {
                            if (tw == wc) { tent = true; break; }
                        }
                        if (!tent) {
                            actions[i] = DIR_BUILD[d];
                            tentative_walls.push_back(wc);
                            built = true;
                            break;
                        }
                    }
                }

                if (!built) {
                    // Move toward best stand position
                    Point best_stand = {-1, -1};
                    int best_sd = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {wc.r + DIRS[d].r, wc.c + DIRS[d].c};
                        if (stand.r < 1 || stand.r > GRID_SIZE || stand.c < 1 || stand.c > GRID_SIZE) continue;
                        if (wall_grid[stand.r][stand.c]) continue;
                        int sd = std::abs(hp.r - stand.r) + std::abs(hp.c - stand.c);
                        if (sd < best_sd) {
                            best_sd = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        actions[i] = bfs_move(hp, best_stand);
                    }
                }
            }
        } else {
            // Move humans to safe center
            for (int i = 0; i < M; i++) {
                Point hp = humans[i].pos;
                int tc = target_c1 + 1 + (i * std::max(0, target_c2 - target_c1 - 2)) / std::max(1, M - 1);
                Point target = {(target_r1 + target_r2) / 2, tc};
                target.r = std::max(target_r1, std::min(target_r2, target.r));
                target.c = std::max(target_c1, std::min(target_c2, target.c));
                actions[i] = bfs_move(hp, target);
            }
        }

        // Validate all actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            Point hpos = humans[i].pos;

            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (!can_build_wall(wp, i)) {
                    actions[i] = '.';
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                Point np = {hpos.r + DIRS[d].r, hpos.c + DIRS[d].c};
                if (np.r < 1 || np.r > GRID_SIZE || np.c < 1 || np.c > GRID_SIZE || wall_grid[np.r][np.c]) {
                    actions[i] = '.';
                }
            }
        }

        // Check for move conflicts (two humans moving to same cell, or moving to a cell being walled)
        std::vector<Point> move_targets(M, {-1, -1});
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
                }
                move_targets[i] = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
            }
        }
        // Cancel moves to tentatively walled cells
        for (int i = 0; i < M; i++) {
            if (move_targets[i].r == -1) continue;
            for (const auto& tw : tentative_walls) {
                if (move_targets[i] == tw) {
                    actions[i] = '.';
                    move_targets[i] = {-1, -1};
                    break;
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply wall builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_BUILD[dd]) { d = dd; break; }
                }
                Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                if (wp.r >= 1 && wp.r <= GRID_SIZE && wp.c >= 1 && wp.c <= GRID_SIZE) {
                    wall_grid[wp.r][wp.c] = true;
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int dd = 0; dd < 4; dd++) {
                    if (a == DIR_MOVE[dd]) { d = dd; break; }
